messages.content:
Extract data from the following document based on the JSON schema.
Return null if the document does not contain information relevant to schema.
Return only the JSON with no explanation text.
The JSON schema is as follows:
{
  "type": "object",
  "properties": {
    "tableData": {
      "type": "array",
      "items": {
        "type": "object",
        "properties": {
          "symbol": {
            "type": "string",
            "description": ""
          },
          "etfName": {
            "type": "string",
            "description": ""
          },
          "closingPrice": {
            "type": "number",
            "description": ""
          },
          "oneDayChange": {
            "type": "number",
            "description": ""
          },
          "ytdPriceChange": {
            "type": "number",
            "description": ""
          }
        }
      }
    },
    "clientServices": {
      "type": "object",
      "properties": {
        "address": {
          "type": "string",
          "description": "Full address of the client representative"
        },
        "consultantId": {
          "type": "string",
          "description": "Client representative id"
        },
        "consultantName": {
          "type": "string",
          "description": "Full name of the client representative"
        }
      },
      "description": "Client representative"
    },
    "portfolioSummary": {
      "type": "object",
      "properties": {
        "changes": {
          "type": "array",
          "items": {
            "type": "object",
            "required": [
              "description",
              "currentPeriod",
              "yearToDate"
            ],
            "properties": {
              "yearToDate": {
                "type": "number",
                "description": "Amount recorded year to date"
              },
              "description": {
                "type": "string",
                "description": "Description of the change"
              },
              "currentPeriod": {
                "type": "number",
                "description": "Amount recorded during the current period"
              }
            }
          },
          "description": "Summary of portfolio changes. Include only changes. Do not include starting and ending balance in this list."
        },
        "ytdBeginningBalance": {
          "type": "number",
          "description": "The year to date starting balance of the portfolio"
        }
      },
      "description": "Overview of the portfolio with balances and changes"
    }
  }
}
